import React, { useContext, useState } from "react";
import { NavLink, useNavigate } from "react-router-dom";
import "../styles/Navbar.css";
import { ThemeContext } from "../context/ThemeContext";

const Navbar = () => {
    const navigate = useNavigate();
    const { theme, toggleTheme } = useContext(ThemeContext);
    const [showThemeMenu, setShowThemeMenu] = useState(false);

    const handleScrollToSection = (e, sectionId) => {
        e.preventDefault();
        navigate("/");
        setTimeout(() => {
            const section = document.getElementById(sectionId);
            if (section) {
                section.scrollIntoView({ behavior: "smooth" });
            }
        }, 100);
    };

    const setThemeDirectly = (selectedTheme) => {
        localStorage.setItem("theme", selectedTheme);
        document.documentElement.setAttribute("data-theme", selectedTheme);
        window.location.reload();
    };

    return (
        <nav className="navbar">
            <div className="logo">ActAware</div>
            <ul className="nav-links">
                <li>
                    <a href="/home" onClick={(e) => handleScrollToSection(e, "body-section")}>Home</a>
                </li>
                <li>
                    <a href="/body" onClick={(e) => handleScrollToSection(e, "body-section")}>About Us</a>
                </li>
                <li>
                    <a href="/blogs" onClick={(e) => handleScrollToSection(e, "blogs-section")}>Feedback</a>
                </li>
                <li>
                    <a href="/blogs" onClick={(e) => handleScrollToSection(e, "blogs-section")}>Sign Language</a>
                </li>
                <li className="theme-toggle-wrapper">
                    <button
                        className="theme-toggle-btn"
                        onClick={() => setShowThemeMenu(!showThemeMenu)}
                    >
                        {theme === "light" ? "☀️" :
                            theme === "dark" ? "🌙" :
                                theme === "blue" ? "🔵" :
                                    theme === "green" ? "🟢" :
                                        theme === "purple" ? "🟣" : "❓"}
                    </button>
                    {showThemeMenu && (
                        <ul className="theme-menu">
                            <li onClick={() => setThemeDirectly("light")}>☀️ Light</li>
                            <li onClick={() => setThemeDirectly("dark")}>🌙 Dark</li>
                            <li onClick={() => setThemeDirectly("blue")}>🔵 Blue</li>
                            <li onClick={() => setThemeDirectly("green")}>🟢 Green</li>
                            <li onClick={() => setThemeDirectly("purple")}>🟣 Purple</li>
                        </ul>
                    )}
                </li>
                <NavLink to="/signup">
                    <button className="signup-btn">Sign Up</button>
                </NavLink>
            </ul>
        </nav>
    );
};

export default Navbar;
